String toneWelcome(AppLocalizations loc, String name, UiTone tone) {
  switch (tone) {
    case UiTone.neutral:
      return loc.welcome_neutral(name);
    case UiTone.professional:
      return loc.welcome_professional(name);
    case UiTone.legal:
      return loc.welcome_legal(name);
  }
}

